def read_CartCurTypeStatus(instrument: minimalmodbus.Instrument):
    """The current cartridge type (see chapter 1.8)

    Schema address : 30201 (0x75f9)
    Protocol address: 200 (0-based)
    FC      : 4
    Type    : uint16  RO
    """
    raw = instrument.read_register(200, functioncode=4)
    _labels = {0: 'unspecified', 1: 'fuel container with custom capacity', 2: 'M5', 3: 'M10', 4: 'M28', 5: 'MT60', 6: 'FM (only register 30201)'}
    return _labels.get(str(raw), f"unknown ({raw})")

